  ('real-estate-moex-00589', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地徵收條例第25條規定，被徵收之土地，所有權人死亡未辦竣繼承登記，其徵收補償費如何 處理？', '["歸屬國庫", "納入平均地權基金", "歸目的事業主管機關所有", "得由部分繼承人按其應繼分領取之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
